#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    const char *days[7] = {"Monday","Tuesday","Wednesday","Thursday","Friday","Saturday","Sunday"};
    for(int i=0;i<T;++i){
        int N; if(scanf("%d", &N)!=1) break;
        if(N>=1 && N<=7) printf("%s", days[N-1]);
        else printf("Invalid input");
        if(i<T-1) printf("\n");
    }
    return 0;
}

